1	<!DOCTYPE html>
2	<html lang="ja">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=no">
6	<title>SpringSense</title>
7	<style>
8	*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
9	html,body{height:100%;overflow:hidden}
10	body{font-family:-apple-system,'Hiragino Sans','Noto Sans JP',sans-serif;background:#EEF5F0;color:#222;display:flex;flex-direction:column}
11	
12	/* Header */
13	.header{background:linear-gradient(135deg,#1B6B3A 0%,#2DAA62 100%);color:#fff;padding:12px 16px 10px;display:flex;align-items:center;gap:10px;flex-shrink:0;box-shadow:0 2px 8px rgba(0,0,0,.2)}
14	.header-icon{width:32px;height:32px;background:rgba(255,255,255,.22);border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:17px;flex-shrink:0}
15	.header-texts{flex:1}
16	.header-title{font-size:15px;font-weight:700;letter-spacing:.2px}
17	.header-sub{font-size:10px;color:rgba(255,255,255,.65);margin-top:1px}
18	.header-disclaimer{font-size:9px;color:#A8F0C0;margin-top:2px;line-height:1.3;font-weight:500}
19	.header-jis{font-size:10px;background:rgba(255,255,255,.18);border:1px solid rgba(255,255,255,.28);border-radius:10px;padding:3px 9px;white-space:nowrap;flex-shrink:0}
20	
21	/* Main */
22	.main{flex:1;overflow:hidden;display:flex;flex-direction:column;padding:10px 12px;gap:8px}
23	
24	/* Material pills */
25	.mat-row{display:flex;gap:6px;overflow-x:auto;flex-shrink:0;padding:2px 0;-webkit-overflow-scrolling:touch;scrollbar-width:none}
26	.mat-row::-webkit-scrollbar{display:none}
27	.mat-pill{border-radius:20px;padding:7px 13px;font-size:12px;font-weight:600;cursor:pointer;border:2px solid transparent;flex-shrink:0;transition:all .15s;user-select:none}
28	.mat-pill.active{background:#1B6B3A;color:#fff;border-color:#1B6B3A}
29	.mat-pill:not(.active){background:#D8EEE0;color:#1B6B3A;border-color:#A8D8B8}
30	
31	/* Result card */
32	.result-card{background:#fff;border-radius:14px;padding:12px 16px;flex-shrink:0;box-shadow:0 1px 6px rgba(0,0,0,.08)}
33	.result-badge-row{display:flex;align-items:center;justify-content:center;gap:10px;margin-bottom:8px}
34	.result-badge{font-size:22px;font-weight:800;padding:6px 20px;border-radius:24px;letter-spacing:.5px}
35	.badge-ok{background:#E8F5E9;color:#1B6B3A}
36	.badge-ng{background:#FCEBEB;color:#A32D2D}
37	.badge-warn{background:#FFF8E1;color:#7A5500}
38	.result-ratio-row{display:flex;align-items:center;gap:10px}
39	.ratio-label{font-size:11px;color:#888;white-space:nowrap}
40	.ratio-bar-bg{flex:1;height:10px;background:#E0E0E0;border-radius:5px;overflow:hidden}
41	.ratio-bar{height:100%;border-radius:5px;transition:width .4s cubic-bezier(.4,0,.2,1)}
42	.ratio-val{font-size:13px;font-weight:700;min-width:44px;text-align:right}
43	.result-hint{text-align:center;font-size:10px;color:#aaa;margin-top:5px}
44	
45	/* Param chips */
46	.chips-grid{display:grid;grid-template-columns:1fr 1fr;gap:7px;flex-shrink:0}
47	.chip{position:relative;border-radius:11px;padding:8px 10px;display:flex;align-items:center;gap:7px;cursor:pointer;overflow:hidden;min-height:52px}
48	.chip-1{background:#F0EBD8}
49	.chip-2{background:#E4EFF5}
50	.chip-3{background:#EBE8F5}
51	.chip-4{background:#E8F5EC}
52	.chip-badge{width:18px;height:18px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:9px;font-weight:700;color:#fff;flex-shrink:0;align-self:flex-start;margin-top:1px}
53	.chip-1 .chip-badge{background:#8A6820}
54	.chip-2 .chip-badge{background:#1A6080}
55	.chip-3 .chip-badge{background:#5040A0}
56	.chip-4 .chip-badge{background:#1B6B3A}
57	.chip-text{flex:1;min-width:0}
58	.chip-label{font-size:9px;color:#888;margin-bottom:2px}
59	.chip-val{font-size:13px;font-weight:700;color:#222;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
60	.chip-sub{font-size:9px;color:#aaa;margin-top:1px}
61	.chip-select{position:absolute;inset:0;opacity:0;cursor:pointer;width:100%;height:100%;font-size:16px}
62	
63	/* Sub result grid */
64	.sub-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:6px;flex-shrink:0}
65	.sub-card{background:#fff;border-radius:10px;padding:7px 8px;box-shadow:0 1px 4px rgba(0,0,0,.06)}
66	.sub-label{font-size:9px;color:#999;margin-bottom:2px}
67	.sub-val{font-size:14px;font-weight:700;color:#222;line-height:1.1}
68	.sub-unit{font-size:9px;color:#aaa}
69	
70	/* Detail collapsible */
71	.detail-section{background:#fff;border-radius:12px;flex:1;min-height:0;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.06)}
72	.detail-inner{height:100%;overflow-y:auto;padding:10px 14px}
73	.detail-row{display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-bottom:.5px solid #f0f0f0}
74	.detail-row:last-child{border-bottom:none}
75	.detail-name{font-size:11px;color:#666}
76	.detail-sym{font-size:10px;color:#aaa;font-style:italic}
77	.detail-val{font-size:12px;font-weight:600;color:#222}
78	.detail-unit{font-size:10px;color:#aaa;margin-left:2px}
79	.detail-row.hl .detail-val{color:#1B6B3A}
80	.detail-sep{height:.5px;background:#eee;margin:3px 0}
81	
82	/* Warning */
83	.warn-box{display:none;background:#FFF8E1;border-left:3px solid #F57C00;border-radius:10px;padding:8px 12px;flex-shrink:0}
84	.warn-box.show{display:block}
85	.warn-t{font-size:11px;font-weight:700;color:#E65100}
86	.warn-d{font-size:10px;color:#BF5000;margin-top:2px}
87	
88	/* Bottom bar */
89	.bottom-bar{flex-shrink:0;background:#E4EDE7;padding:8px 12px;border-top:1px solid #D0DACE}
90	.btn-share{width:100%;padding:13px 8px;background:#1B6B3A;color:#fff;border:none;border-radius:12px;font-size:14px;font-weight:600;cursor:pointer;letter-spacing:.2px}
91	.btn-share:active{background:#155530}
92	</style>
93	</head>
94	<body>
95	
96	<div class="header">
97	  <div class="header-icon">🌀</div>
98	  <div class="header-texts">
99	    <div class="header-title">SpringSense <span style="font-size:11px;font-weight:400;opacity:.7">v1.0.0</span></div>
100	    <div class="header-sub">© 2026 BoltSense (t.makoto). All rights reserved.</div>
101	    <div class="header-disclaimer">計算結果は参考値です。設計への適用は技術者の判断で行ってください。</div>
102	  </div>
103	  <div class="header-jis">JIS B 2704</div>
104	</div>
105	
106	<div class="main">
107	
108	  <!-- 材料選択 -->
109	  <div class="mat-row">
110	    <div class="mat-pill active" data-mat="SW-B" onclick="selectMat(this)">SW-B</div>
111	    <div class="mat-pill" data-mat="SW-C" onclick="selectMat(this)">SW-C</div>
112	    <div class="mat-pill" data-mat="SWP-A" onclick="selectMat(this)">SWP-A</div>
113	    <div class="mat-pill" data-mat="SWO-A" onclick="selectMat(this)">SWO-A</div>
114	    <div class="mat-pill" data-mat="SWOSC-B" onclick="selectMat(this)">SWOSC-B</div>
115	    <div class="mat-pill" data-mat="SUS304-WPB" onclick="selectMat(this)">SUS304</div>
116	  </div>
117	
118	  <!-- 判定カード -->
119	  <div class="result-card">
120	    <div class="result-badge-row">
121	      <div class="result-badge badge-ok" id="res-badge">計算中</div>
122	    </div>
123	    <div class="result-ratio-row">
124	      <div class="ratio-label">τ/σB</div>
125	      <div class="ratio-bar-bg"><div class="ratio-bar" id="ratio-bar" style="width:0%;background:#1B6B3A"></div></div>
126	      <div class="ratio-val" id="res-ratio">—</div>
127	    </div>
128	    <div class="result-hint">JIS B 2704 許容値: τ/σB ≤ 0.45</div>
129	  </div>
130	
131	  <!-- パラメータチップ -->
132	  <div class="chips-grid">
133	    <!-- 線径 d -->
134	    <div class="chip chip-1">
135	      <div class="chip-badge">d</div>
136	      <div class="chip-text">
137	        <div class="chip-label">線径 d</div>
138	        <div class="chip-val" id="chip-d-val">2.0 mm</div>
139	        <div class="chip-sub">JIS標準線径</div>
140	      </div>
141	      <select id="sel-d" class="chip-select" onchange="onChipChange()">
142	        <option value="0.5">0.5 mm</option>
143	        <option value="0.6">0.6 mm</option>
144	        <option value="0.7">0.7 mm</option>
145	        <option value="0.8">0.8 mm</option>
146	        <option value="1.0">1.0 mm</option>
147	        <option value="1.2">1.2 mm</option>
148	        <option value="1.4">1.4 mm</option>
149	        <option value="1.6">1.6 mm</option>
150	        <option value="1.8">1.8 mm</option>
151	        <option value="2.0" selected>2.0 mm</option>
152	        <option value="2.3">2.3 mm</option>
153	        <option value="2.6">2.6 mm</option>
154	        <option value="2.9">2.9 mm</option>
155	        <option value="3.2">3.2 mm</option>
156	        <option value="3.5">3.5 mm</option>
157	        <option value="4.0">4.0 mm</option>
158	        <option value="4.5">4.5 mm</option>
159	        <option value="5.0">5.0 mm</option>
160	        <option value="6.0">6.0 mm</option>
161	        <option value="7.0">7.0 mm</option>
162	        <option value="8.0">8.0 mm</option>
163	        <option value="10.0">10.0 mm</option>
164	        <option value="12.0">12.0 mm</option>
165	        <option value="13.0">13.0 mm</option>
166	      </select>
167	    </div>
168	    <!-- 有効巻数 Na -->
169	    <div class="chip chip-2">
170	      <div class="chip-badge">Na</div>
171	      <div class="chip-text">
172	        <div class="chip-label">有効巻数 Na</div>
173	        <div class="chip-val" id="chip-na-val">5 巻</div>
174	        <div class="chip-sub">総巻数 = Na + 2</div>
175	      </div>
176	      <select id="sel-na" class="chip-select" onchange="onChipChange()">
177	        <option value="3">3 巻</option>
178	        <option value="3.5">3.5 巻</option>
179	        <option value="4">4 巻</option>
180	        <option value="4.5">4.5 巻</option>
181	        <option value="5" selected>5 巻</option>
182	        <option value="5.5">5.5 巻</option>
183	        <option value="6">6 巻</option>
184	        <option value="7">7 巻</option>
185	        <option value="8">8 巻</option>
186	        <option value="9">9 巻</option>
187	        <option value="10">10 巻</option>
188	        <option value="12">12 巻</option>
189	        <option value="15">15 巻</option>
190	        <option value="18">18 巻</option>
191	        <option value="20">20 巻</option>
192	        <option value="25">25 巻</option>
193	      </select>
194	    </div>
195	    <!-- コイル中心径 D -->
196	    <div class="chip chip-3" style="cursor:default">
197	      <div class="chip-badge">D</div>
198	      <div class="chip-text">
199	        <div class="chip-label">中心径 D (mm)</div>
200	        <input type="number" id="inp-D" value="15" min="1" max="500" step="0.5"
201	          style="font-size:16px;font-weight:700;width:100%;background:none;border:none;outline:none;color:#222;padding:0;margin-top:2px"
202	          oninput="calc()">
203	      </div>
204	    </div>
205	    <!-- 荷重 P -->
206	    <div class="chip chip-4" style="cursor:default">
207	      <div class="chip-badge">P</div>
208	      <div class="chip-text">
209	        <div class="chip-label">荷重 P (N)</div>
210	        <input type="number" id="inp-P" value="50" min="0.1" max="100000" step="1"
211	          style="font-size:16px;font-weight:700;width:100%;background:none;border:none;outline:none;color:#222;padding:0;margin-top:2px"
212	          oninput="calc()">
213	      </div>
214	    </div>
215	  </div>
216	
217	  <!-- 警告 -->
218	  <div class="warn-box" id="warn-box">
219	    <div class="warn-t" id="warn-title">警告</div>
220	    <div class="warn-d" id="warn-detail"></div>
221	  </div>
222	
223	  <!-- サブ結果 -->
224	  <div class="sub-grid">
225	    <div class="sub-card">
226	      <div class="sub-label">ばね定数 k</div>
227	      <div><span class="sub-val" id="res-k">—</span><span class="sub-unit"> N/mm</span></div>
228	    </div>
229	    <div class="sub-card">
230	      <div class="sub-label">たわみ δ</div>
231	      <div><span class="sub-val" id="res-d">—</span><span class="sub-unit"> mm</span></div>
232	    </div>
233	    <div class="sub-card">
234	      <div class="sub-label">応力 τ</div>
235	      <div><span class="sub-val" id="res-tau">—</span><span class="sub-unit"> MPa</span></div>
236	    </div>
237	    <div class="sub-card">
238	      <div class="sub-label">密着高さ Lc</div>
239	      <div><span class="sub-val" id="res-lc">—</span><span class="sub-unit"> mm</span></div>
240	    </div>
241	  </div>
242	
243	  <!-- 詳細 -->
244	  <div class="detail-section">
245	    <div class="detail-inner" id="detail-inner">
246	      <div style="font-size:11px;color:#aaa;text-align:center;padding:10px">計算すると詳細が表示されます</div>
247	    </div>
248	  </div>
249	
250	</div>
251	
252	<div class="bottom-bar">
253	  <button class="btn-share" onclick="shareResult()">結果を保存・共有</button>
254	</div>
255	
256	<script>
257	// ===== 材料データ (JIS最小引張強さ σB) =====
258	const MATS = {
259	  'SW-B':    { jis:'JIS G3521', G:78500, sigma:[
260	    {d:0.5,s:1910},{d:0.6,s:1810},{d:0.7,s:1770},{d:0.8,s:1770},
261	    {d:1.0,s:1720},{d:1.2,s:1670},{d:1.4,s:1620},{d:1.6,s:1570},
262	    {d:1.8,s:1520},{d:2.0,s:1470},{d:2.3,s:1420},{d:2.6,s:1420},
263	    {d:2.9,s:1370},{d:3.2,s:1370},{d:3.5,s:1370},{d:4.0,s:1370},
264	    {d:4.5,s:1320},{d:5.0,s:1320},{d:6.0,s:1230},{d:7.0,s:1180},
265	    {d:8.0,s:1180},{d:10.0,s:1130},{d:12.0,s:1080},{d:13.0,s:1030}
266	  ]},
267	  'SW-C':    { jis:'JIS G3521', G:78500, sigma:[
268	    {d:0.5,s:2210},{d:0.6,s:2110},{d:0.7,s:2060},{d:0.8,s:2010},
269	    {d:1.0,s:1960},{d:1.2,s:1910},{d:1.4,s:1860},{d:1.6,s:1810},
270	    {d:1.8,s:1770},{d:2.0,s:1720},{d:2.3,s:1670},{d:2.6,s:1670},
271	    {d:2.9,s:1620},{d:3.2,s:1570},{d:3.5,s:1570},{d:4.0,s:1570},
272	    {d:4.5,s:1520},{d:5.0,s:1520},{d:6.0,s:1420},{d:7.0,s:1370},
273	    {d:8.0,s:1370},{d:10.0,s:1320},{d:12.0,s:1270},{d:13.0,s:1230}
274	  ]},
275	  'SWP-A':   { jis:'JIS G3522', G:78500, sigma:[
276	    {d:0.5,s:2300},{d:0.6,s:2210},{d:0.7,s:2160},{d:0.8,s:2110},
277	    {d:1.0,s:2060},{d:1.2,s:2010},{d:1.4,s:1960},{d:1.6,s:1910},
278	    {d:1.8,s:1860},{d:2.0,s:1810},{d:2.3,s:1770},{d:2.6,s:1770},
279	    {d:2.9,s:1720},{d:3.2,s:1670},{d:3.5,s:1670},{d:4.0,s:1670},
280	    {d:4.5,s:1620},{d:5.0,s:1620},{d:6.0,s:1520},{d:7.0,s:1470},
281	    {d:8.0,s:1470},{d:10.0,s:1420}
282	  ]},
283	  'SWO-A':   { jis:'JIS G3560', G:78500, sigma:[
284	    {d:2.0,s:1570},{d:2.3,s:1570},{d:2.6,s:1570},{d:2.9,s:1520},
285	    {d:3.2,s:1470},{d:3.5,s:1470},{d:4.0,s:1420},{d:4.5,s:1370},
286	    {d:5.0,s:1370},{d:6.0,s:1320},{d:7.0,s:1270},{d:8.0,s:1270},
287	    {d:10.0,s:1230},{d:12.0,s:1180}
288	  ]},
289	  'SWOSC-B': { jis:'JIS G3560', G:78500, sigma:[
290	    {d:1.0,s:1960},{d:1.2,s:1960},{d:1.4,s:1960},{d:1.6,s:1960},
291	    {d:1.8,s:1960},{d:2.0,s:1910},{d:2.3,s:1910},{d:2.6,s:1910},
292	    {d:2.9,s:1910},{d:3.2,s:1860},{d:3.5,s:1860},{d:4.0,s:1810},
293	    {d:4.5,s:1760},{d:5.0,s:1760},{d:6.0,s:1710},{d:7.0,s:1660},
294	    {d:8.0,s:1660},{d:10.0,s:1660},{d:12.0,s:1660}
295	  ]},
296	  'SUS304-WPB':{ jis:'JIS G4314', G:68500, sigma:[
297	    {d:0.5,s:2000},{d:0.6,s:1950},{d:0.8,s:1950},{d:1.0,s:1850},
298	    {d:1.4,s:1750},{d:2.0,s:1650},{d:2.6,s:1550},{d:4.0,s:1450},
299	    {d:6.0,s:1350},{d:8.0,s:1270},{d:10.0,s:980},{d:12.0,s:880}
300	  ]}
301	};
302	
303	let currentMat = 'SW-B';
304	
305	function ge(id){ return document.getElementById(id); }
306	function fmt(v, n){ return (v===null||isNaN(v)||!isFinite(v)) ? '—' : v.toFixed(n); }
307	
308	function getSigmaB(matKey, d){
309	  const tbl = MATS[matKey].sigma;
310	  if(!tbl) return 1200;
311	  for(let i=0;i<tbl.length;i++){
312	    if(d<=tbl[i].d) return tbl[i].s;
313	  }
314	  return tbl[tbl.length-1].s;
315	}
316	
317	function selectMat(el){
318	  document.querySelectorAll('.mat-pill').forEach(p=>p.classList.remove('active'));
319	  el.classList.add('active');
320	  currentMat = el.dataset.mat;
321	  calc();
322	}
323	
324	function onChipChange(){
325	  ge('chip-d-val').textContent  = ge('sel-d').value + ' mm';
326	  ge('chip-na-val').textContent = ge('sel-na').value + ' 巻';
327	  calc();
328	}
329	
330	function calc(){
331	  const d  = parseFloat(ge('sel-d').value);
332	  const Na = parseFloat(ge('sel-na').value);
333	  const D  = parseFloat(ge('inp-D').value);
334	  const P  = parseFloat(ge('inp-P').value);
335	  const mat = MATS[currentMat];
336	  if(!mat){ setError('材料データが見つかりません'); return; }
337	  const G = mat.G;
338	  const sigmaB = getSigmaB(currentMat, d);
339	
340	  // Validate
341	  if(isNaN(D)||D<=0||isNaN(P)||P<0||isNaN(d)||isNaN(Na)){
342	    setError('入力値を確認してください'); return;
343	  }
344	
345	  // Core calculations (JIS B 2704)
346	  const C = D / d;                                           // ばね指数
347	  if(C < 2){ setError('ばね指数 C < 2: 線径が大きすぎます'); return; }
348	  const K  = (4*C-1)/(4*C-4) + 0.615/C;                    // Wahl係数
349	  const k  = G * Math.pow(d,4) / (8 * Math.pow(D,3) * Na); // ばね定数 (N/mm)
350	  const delta = k > 0 ? P / k : 0;                          // たわみ (mm)
351	  const tau = 8 * P * D * K / (Math.PI * Math.pow(d,3));    // 最大せん断応力 (MPa)
352	  const Lc  = (Na + 2) * d;                                 // 密着高さ (mm)
353	  const ratio = tau / sigmaB;                                // 応力比
354	
355	  // Safety checks
356	  const stressOK = ratio <= 0.45;
357	  const cRange   = C >= 4 && C <= 14;
358	  const isSafe   = stressOK && cRange;
359	
360	  // Badge
361	  const badge = ge('res-badge');
362	  if(isSafe){
363	    badge.className='result-badge badge-ok'; badge.textContent='安全 OK';
364	  } else if(!stressOK){
365	    badge.className='result-badge badge-ng'; badge.textContent='応力超過 NG';
366	  } else {
367	    badge.className='result-badge badge-warn'; badge.textContent='指数注意';
368	  }
369	
370	  // Ratio bar
371	  const pct = Math.min(ratio / 0.45 * 100, 100);
372	  const barColor = ratio <= 0.35 ? '#1B6B3A' : ratio <= 0.45 ? '#F57C00' : '#C62828';
373	  ge('ratio-bar').style.width  = pct.toFixed(1) + '%';
374	  ge('ratio-bar').style.background = barColor;
375	  ge('res-ratio').textContent = fmt(ratio, 3);
376	  ge('res-ratio').style.color = barColor;
377	
378	  // Sub results
379	  ge('res-k').textContent  = fmt(k, 3);
380	  ge('res-d').textContent  = fmt(delta, 2);
381	  ge('res-tau').textContent = fmt(tau, 1);
382	  ge('res-lc').textContent  = fmt(Lc, 2);
383	
384	  // Warning
385	  const warnBox = ge('warn-box');
386	  const warnings = [];
387	  if(!stressOK)  warnings.push(`応力超過: τ/σB = ${fmt(ratio,4)} > 0.45。線径を太くするかコイル径を大きくしてください。`);
388	  if(C < 4)      warnings.push(`ばね指数 C = ${fmt(C,2)} < 4（推奨範囲）。コイル径を大きくするか線径を細くしてください。`);
389	  if(C > 14)     warnings.push(`ばね指数 C = ${fmt(C,2)} > 14（推奨範囲）。座屈リスクが増加します。`);
390	  if(warnings.length > 0){
391	    warnBox.classList.add('show');
392	    ge('warn-title').textContent = warnings.length > 1 ? `⚠ ${warnings.length}件の警告` : '⚠ 警告';
393	    ge('warn-detail').textContent = warnings.join(' / ');
394	  } else {
395	    warnBox.classList.remove('show');
396	  }
397	
398	  // Detail rows
399	  const rows = [
400	    ['線径',        'd',          fmt(d,2),             'mm'],
401	    ['中心径',      'D',          fmt(D,2),             'mm'],
402	    ['外径',        'Do=D+d',     fmt(D+d,2),           'mm'],
403	    ['内径',        'Di=D-d',     fmt(D-d,2),           'mm'],
404	    ['有効巻数',    'Na',         fmt(Na,1),            '巻'],
405	    ['総巻数',      'Nt=Na+2',    fmt(Na+2,1),          '巻'],
406	    null,
407	    ['横弾性係数',  'G',          G.toLocaleString(),   'MPa'],
408	    ['引張強さ',    'σB',         sigmaB.toLocaleString(),'N/mm²'],
409	    ['ばね定数',    'k',          fmt(k,4),             'N/mm',  true],
410	    ['ばね指数',    'C=D/d',      fmt(C,3),             '—',     true],
411	    ['Wahl係数',    'K',          fmt(K,4),             '—',     true],
412	    null,
413	    ['荷重',        'P',          fmt(P,2),             'N'],
414	    ['たわみ',      'δ=P/k',      fmt(delta,3),         'mm',    true],
415	    ['せん断応力',  'τ',          fmt(tau,2),           'MPa',   true],
416	    ['応力比',      'τ/σB',       fmt(ratio,4),         '—',     true],
417	    null,
418	    ['密着高さ',    'Lc=(Na+2)d', fmt(Lc,2),            'mm'],
419	  ];
420	
421	  let html = '';
422	  rows.forEach(r => {
423	    if(!r){ html += '<div class="detail-sep"></div>'; return; }
424	    const [name,sym,val,unit,hl] = r;
425	    html += `<div class="detail-row${hl?' hl':''}">
426	      <span class="detail-name">${name} <span class="detail-sym">${sym}</span></span>
427	      <span><span class="detail-val">${val}</span><span class="detail-unit">${unit}</span></span>
428	    </div>`;
429	  });
430	  ge('detail-inner').innerHTML = html;
431	}
432	
433	function setError(msg){
434	  const badge = ge('res-badge');
435	  badge.className='result-badge badge-ng'; badge.textContent='入力エラー';
436	  ge('ratio-bar').style.width='0%';
437	  ge('res-ratio').textContent='—';
438	  ge('res-k').textContent=ge('res-d').textContent=ge('res-tau').textContent=ge('res-lc').textContent='—';
439	  ge('detail-inner').innerHTML=`<div style="font-size:11px;color:#A32D2D;text-align:center;padding:10px">${msg}</div>`;
440	  ge('warn-box').classList.remove('show');
441	}
442	
443	function shareResult(){
444	  const d   = ge('sel-d').value;
445	  const Na  = ge('sel-na').value;
446	  const D   = ge('inp-D').value;
447	  const P   = ge('inp-P').value;
448	  const k   = ge('res-k').textContent;
449	  const tau = ge('res-tau').textContent;
450	  const rat = ge('res-ratio').textContent;
451	  const bdg = ge('res-badge').textContent;
452	  const lc  = ge('res-lc').textContent;
453	  const text = [
454	    'SpringSense コイルばね計算（JIS B 2704）',
455	    `材料: ${currentMat} / d=${d}mm / D=${D}mm / Na=${Na}`,
456	    `荷重: P=${P} N`,
457	    `ばね定数: k=${k} N/mm`,
458	    `せん断応力: τ=${tau} MPa（τ/σB=${rat}）`,
459	    `密着高さ: Lc=${lc} mm`,
460	    `判定: ${bdg}`
461	  ].join('\n');
462	
463	  if(navigator.share){
464	    navigator.share({title:'SpringSense 計算結果', text});
465	  } else if(navigator.clipboard){
466	    navigator.clipboard.writeText(text).then(()=>alert('クリップボードにコピーしました'));
467	  }
468	}
469	
470	// 初期化
471	onChipChange();
472	calc();
473	</script>
474	</body>
475	</html>
