/**
 * SpringSense 計算検証スクリプト
 * spring-calc-mobile.html の計算ロジックを Node.js で再現し、
 * 手計算値との照合を行う。
 *
 * 実行: node verify-calc.js
 */

// ===== 材料データ (JIS最小引張強さ σB) =====
const MATS = {
  'SW-B':    { jis:'JIS G3521', G:78500, sigma:[
    {d:0.5,s:1910},{d:0.6,s:1810},{d:0.7,s:1770},{d:0.8,s:1770},
    {d:1.0,s:1720},{d:1.2,s:1670},{d:1.4,s:1620},{d:1.6,s:1570},
    {d:1.8,s:1520},{d:2.0,s:1470},{d:2.3,s:1420},{d:2.6,s:1420},
    {d:2.9,s:1370},{d:3.2,s:1370},{d:3.5,s:1370},{d:4.0,s:1370},
    {d:4.5,s:1320},{d:5.0,s:1320},{d:6.0,s:1230},{d:7.0,s:1180},
    {d:8.0,s:1180},{d:10.0,s:1130},{d:12.0,s:1080},{d:13.0,s:1030}
  ]},
  'SW-C':    { jis:'JIS G3521', G:78500, sigma:[
    {d:0.5,s:2210},{d:0.6,s:2110},{d:0.7,s:2060},{d:0.8,s:2010},
    {d:1.0,s:1960},{d:1.2,s:1910},{d:1.4,s:1860},{d:1.6,s:1810},
    {d:1.8,s:1770},{d:2.0,s:1720},{d:2.3,s:1670},{d:2.6,s:1670},
    {d:2.9,s:1620},{d:3.2,s:1570},{d:3.5,s:1570},{d:4.0,s:1570},
    {d:4.5,s:1520},{d:5.0,s:1520},{d:6.0,s:1420},{d:7.0,s:1370},
    {d:8.0,s:1370},{d:10.0,s:1320},{d:12.0,s:1270},{d:13.0,s:1230}
  ]},
  'SWP-A':   { jis:'JIS G3522', G:78500, sigma:[
    {d:0.5,s:2300},{d:0.6,s:2210},{d:0.7,s:2160},{d:0.8,s:2110},
    {d:1.0,s:2060},{d:1.2,s:2010},{d:1.4,s:1960},{d:1.6,s:1910},
    {d:1.8,s:1860},{d:2.0,s:1810},{d:2.3,s:1770},{d:2.6,s:1770},
    {d:2.9,s:1720},{d:3.2,s:1670},{d:3.5,s:1670},{d:4.0,s:1670},
    {d:4.5,s:1620},{d:5.0,s:1620},{d:6.0,s:1520},{d:7.0,s:1470},
    {d:8.0,s:1470},{d:10.0,s:1420}
  ]},
  'SWO-A':   { jis:'JIS G3560', G:78500, sigma:[
    {d:2.0,s:1570},{d:2.3,s:1570},{d:2.6,s:1570},{d:2.9,s:1520},
    {d:3.2,s:1470},{d:3.5,s:1470},{d:4.0,s:1420},{d:4.5,s:1370},
    {d:5.0,s:1370},{d:6.0,s:1320},{d:7.0,s:1270},{d:8.0,s:1270},
    {d:10.0,s:1230},{d:12.0,s:1180}
  ]},
  'SWOSC-B': { jis:'JIS G3560', G:78500, sigma:[
    {d:1.0,s:1960},{d:1.2,s:1960},{d:1.4,s:1960},{d:1.6,s:1960},
    {d:1.8,s:1960},{d:2.0,s:1910},{d:2.3,s:1910},{d:2.6,s:1910},
    {d:2.9,s:1910},{d:3.2,s:1860},{d:3.5,s:1860},{d:4.0,s:1810},
    {d:4.5,s:1760},{d:5.0,s:1760},{d:6.0,s:1710},{d:7.0,s:1660},
    {d:8.0,s:1660},{d:10.0,s:1660},{d:12.0,s:1660}
  ]},
  'SUS304-WPB':{ jis:'JIS G4314', G:68500, sigma:[
    {d:0.5,s:2000},{d:0.6,s:1950},{d:0.8,s:1950},{d:1.0,s:1850},
    {d:1.4,s:1750},{d:2.0,s:1650},{d:2.6,s:1550},{d:4.0,s:1450},
    {d:6.0,s:1350},{d:8.0,s:1270},{d:10.0,s:980},{d:12.0,s:880}
  ]}
};

function getSigmaB(matKey, d) {
  const tbl = MATS[matKey].sigma;
  if (!tbl) return 1200;
  for (let i = 0; i < tbl.length; i++) {
    if (d <= tbl[i].d) return tbl[i].s;
  }
  return tbl[tbl.length - 1].s;
}

function calcSpring(matKey, d, D, Na, P) {
  const mat = MATS[matKey];
  const G = mat.G;
  const sigmaB = getSigmaB(matKey, d);
  const C = D / d;
  const K = (4*C-1)/(4*C-4) + 0.615/C;
  const k = G * Math.pow(d,4) / (8 * Math.pow(D,3) * Na);
  const delta = P / k;
  const tau = 8 * P * D * K / (Math.PI * Math.pow(d,3));
  const Lc = (Na + 2) * d;
  const ratio = tau / sigmaB;
  const stressOK = ratio <= 0.45;
  const cRange = C >= 4 && C <= 14;
  const verdict = stressOK && cRange ? '安全 OK' : !stressOK ? '応力超過 NG' : '指数注意';

  return { C, K, k, delta, tau, Lc, sigmaB, G, ratio, verdict };
}

function fmt(v, n) { return v.toFixed(n); }

// ===== テストケース定義 =====
const CASES = [
  {
    name: 'ケース1: 基本例（SW-B, d=2.0, D=15, Na=5, P=50）',
    mat: 'SW-B', d: 2.0, D: 15, Na: 5, P: 50,
    // 手計算期待値
    expected: {
      C:    7.500,
      K:    1.1974,  // (4*7.5-1)/(4*7.5-4) + 0.615/7.5 = 29/26 + 0.082
      k:    9.3037,  // 78500*16/(8*3375*5) = 1256000/135000
      delta:5.374,   // 50/9.3037
      tau:  285.5,   // 8*50*15*1.1974/(π*8) ≈ 285.5 MPa
      Lc:   14.00,
      sigmaB: 1470,
      ratio: 0.1942, // 285.5/1470
      verdict: '安全 OK'
    }
  },
  {
    name: 'ケース2: 中規模（SW-C, d=3.2, D=20, Na=8, P=100）',
    mat: 'SW-C', d: 3.2, D: 20, Na: 8, P: 100,
    expected: {
      C:    6.250,   // 20/3.2
      K:    1.2444,  // (4*6.25-1)/(4*6.25-4) + 0.615/6.25 = 24/21 + 0.0984
      k:    5.1006,  // 78500*(3.2^4)/(8*(20^3)*8) = 78500*104.858/204800
      delta:19.605,  // 100/5.1006
      tau:  150.5,   // 8*100*20*1.2444/(π*32.768)
      Lc:   32.00,   // (8+2)*3.2
      sigmaB: 1570,
      ratio: 0.0958,
      verdict: '安全 OK'
    }
  },
  {
    name: 'ケース3: 境界条件 C≈4（SW-C, d=4.0, D=16, Na=10, P=200）',
    mat: 'SW-C', d: 4.0, D: 16, Na: 10, P: 200,
    expected: {
      C:    4.000,   // 16/4
      K:    1.3980,  // (16-1)/(16-4) + 0.615/4 = 15/12 + 0.154 = 1.25+0.154
      k:    6.1328,  // 78500*(4^4)/(8*(16^3)*10) = 78500*256/327680
      delta:32.612,
      tau:  440.4,   // 8*200*16*1.398/(π*64)
      Lc:   48.00,   // 12*4
      sigmaB: 1570,
      ratio: 0.2805,
      verdict: '安全 OK'
    }
  },
  {
    name: 'ケース4: 応力超過確認（SW-B, d=1.0, D=15, Na=5, P=200）',
    mat: 'SW-B', d: 1.0, D: 15, Na: 5, P: 200,
    expected: {
      C:    15.0,    // 15/1 → C>14 → 指数注意も発生
      K:    1.1185,  // (60-1)/(60-4) + 0.615/15 = 59/56 + 0.041
      k:    0.1303,  // 78500*1/(8*3375*5)
      delta:1535.0,
      tau:  16249,   // 非常に高い
      Lc:   7.00,
      sigmaB: 1720,
      ratio: 9.448,
      verdict: '応力超過 NG'
    }
  },
  {
    name: 'ケース5: SUS304（d=2.0, D=20, Na=6, P=80）',
    mat: 'SUS304-WPB', d: 2.0, D: 20, Na: 6, P: 80,
    expected: {
      C:    10.0,
      K:    1.1452,  // (40-1)/(40-4) + 0.615/10 = 39/36 + 0.0615
      k:    2.9948,  // 68500*16/(8*8000*6) = 1096000/384000
      delta:26.71,
      tau:  1175.0,  // rough
      Lc:   16.00,
      sigmaB: 1650,
      ratio: 0.712,
      verdict: '応力超過 NG'
    }
  },
  {
    name: 'ケース6: SWP-A 高品質ばね（d=3.5, D=25, Na=7, P=150）',
    mat: 'SWP-A', d: 3.5, D: 25, Na: 7, P: 150,
    expected: {
      C:    7.143,
      K:    1.2022,
      k:    5.2167,
      delta:28.76,
      tau:  254.5,
      Lc:   31.50,
      sigmaB: 1670,
      ratio: 0.1524,
      verdict: '安全 OK'
    }
  }
];

// ===== 検証実行 =====
console.log('='.repeat(70));
console.log('  SpringSense 計算検証レポート');
console.log('  JIS B 2704 準拠 / ' + new Date().toLocaleString('ja-JP'));
console.log('='.repeat(70));

let allPass = true;

CASES.forEach((tc, idx) => {
  const r = calcSpring(tc.mat, tc.d, tc.D, tc.Na, tc.P);
  const e = tc.expected;
  console.log('\n' + tc.name);
  console.log('-'.repeat(60));

  const checks = [
    { name: 'C (ばね指数)',   calc: r.C,      exp: e.C,      tol: 0.001 },
    { name: 'K (Wahl係数)',  calc: r.K,      exp: e.K,      tol: 0.005 },
    { name: 'k (N/mm)',      calc: r.k,      exp: e.k,      tol: 0.05  },
    { name: 'δ (mm)',        calc: r.delta,  exp: e.delta,  tol: 0.5   },
    { name: 'τ (MPa)',       calc: r.tau,    exp: e.tau,    tol: 5.0   },
    { name: 'Lc (mm)',       calc: r.Lc,     exp: e.Lc,     tol: 0.01  },
    { name: 'σB (MPa)',      calc: r.sigmaB, exp: e.sigmaB, tol: 1     },
    { name: 'τ/σB 比',       calc: r.ratio,  exp: e.ratio,  tol: 0.01  },
  ];

  let casePass = true;
  checks.forEach(c => {
    const diff = Math.abs(c.calc - c.exp);
    const pass = diff <= c.tol;
    if (!pass) { allPass = false; casePass = false; }
    const mark = pass ? '✓' : '✗';
    console.log(`  ${mark} ${c.name.padEnd(14)}: 計算値=${fmt(c.calc,4).padStart(10)}  期待値=${fmt(c.exp,4).padStart(10)}  差分=${fmt(diff,4).padStart(8)}  (許容:±${c.tol})`);
  });

  const verdictPass = r.verdict === e.verdict;
  if (!verdictPass) { allPass = false; casePass = false; }
  console.log(`  ${verdictPass?'✓':'✗'} 判定          : 計算値=${r.verdict.padEnd(10)}  期待値=${e.verdict}`);

  console.log(`  → ケース総合: ${casePass ? '✅ PASS' : '❌ FAIL'}`);
});

// ===== getSigmaB 境界テスト =====
console.log('\n' + '='.repeat(70));
console.log('  getSigmaB 境界値テスト');
console.log('='.repeat(70));

const sigmaTests = [
  { mat: 'SW-B', d: 2.0,  expected: 1470, note: '完全一致' },
  { mat: 'SW-B', d: 2.1,  expected: 1420, note: 'd=2.3の値を使用（切り上げ）' },
  { mat: 'SW-B', d: 0.5,  expected: 1910, note: '最小線径' },
  { mat: 'SW-B', d: 13.0, expected: 1030, note: '最大線径' },
  { mat: 'SWO-A', d: 1.0, expected: 1570, note: 'SWO-Aのmin=d2.0、d=1.0はd=2.0の値' },
  { mat: 'SWOSC-B', d: 0.5, expected: 1960, note: 'SWOSC-B min=d1.0' },
  { mat: 'SUS304-WPB', d: 2.6, expected: 1550, note: '完全一致' },
];

sigmaTests.forEach(t => {
  const calc = getSigmaB(t.mat, t.d);
  const pass = calc === t.expected;
  if (!pass) allPass = false;
  console.log(`  ${pass?'✓':'✗'} ${t.mat} d=${t.d}: σB=${calc} MPa (期待:${t.expected}) — ${t.note}`);
});

// ===== 最終判定 =====
console.log('\n' + '='.repeat(70));
console.log(`  最終結果: ${allPass ? '✅ 全ケース PASS — 実装は正確です' : '❌ 一部 FAIL — 要修正'}`);
console.log('='.repeat(70));

